import React, { useState } from 'react';
import axios from 'axios';
import Editor from '@monaco-editor/react';
import { Upload, FileCode, ShieldCheck, RefreshCw } from 'lucide-react';
import RiskProfile from './components/RiskProfile';

function App() {
  const [file, setFile] = useState(null);
  const [code, setCode] = useState("// Upload a PHP file to begin analysis...");
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleFileUpload = (e) => {
    const uploadedFile = e.target.files[0];
    if (uploadedFile) {
      setFile(uploadedFile);
      const reader = new FileReader();
      reader.onload = (e) => setCode(e.target.result);
      reader.readAsText(uploadedFile);
    }
  };

  const analyzeMalware = async () => {
    if (!file) return alert("Please select a file first!");
    
    setLoading(true);
    const formData = new FormData();
    formData.append("file", file);

    try {
      const response = await axios.post("http://localhost:8000/scan", formData);
      setResults(response.data.results);
    } catch (error) {
      console.error("Analysis failed", error);
      alert("Error connecting to CodeBERT backend.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 p-8 font-sans">
      {/* Header */}
      <header className="max-w-7xl mx-auto mb-8 flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-extrabold text-gray-900 flex items-center gap-3">
            <ShieldCheck className="text-blue-600" size={36} />
            PHPSentinel <span className="text-sm font-light text-gray-400">v1.0 (Thesis Alpha)</span>
          </h1>
          <p className="text-gray-500">Semantic Deobfuscation & Malware Intelligence</p>
        </div>
      </header>

      <main className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Editor & Upload */}
        <div className="lg:col-span-2 space-y-4">
          <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-2 text-gray-600">
                <FileCode size={20} />
                <span className="font-medium">{file ? file.name : "Source Code Viewer"}</span>
              </div>
              <div className="flex gap-2">
                <label className="cursor-pointer bg-gray-100 hover:bg-gray-200 px-4 py-2 rounded-lg text-sm transition-colors flex items-center gap-2">
                  <Upload size={16} />
                  Select File
                  <input type="file" className="hidden" onChange={handleFileUpload} accept=".php" />
                </label>
                <button 
                  onClick={analyzeMalware}
                  disabled={loading}
                  className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg text-sm font-bold flex items-center gap-2 disabled:opacity-50"
                >
                  {loading ? <RefreshCw className="animate-spin" size={16} /> : "Scan Code"}
                </button>
              </div>
            </div>
            
            <div className="border rounded-lg overflow-hidden h-[500px]">
              <Editor
                height="100%"
                defaultLanguage="php"
                theme="vs-dark"
                value={code}
                options={{ readOnly: true, minimap: { enabled: false } }}
              />
            </div>
          </div>
        </div>

        {/* Right Column: Results */}
        <div className="lg:col-span-1">
          {results ? (
            <RiskProfile data={results} />
          ) : (
            <div className="bg-white p-12 rounded-xl border-2 border-dashed border-gray-300 text-center text-gray-400">
              <ShieldCheck size={48} className="mx-auto mb-4 opacity-20" />
              <p>Upload and scan a file to generate a behavioral risk profile.</p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

export default App;
